if ((#MotionSensor #Kitchen).motionSensor_motion == true) {
if (triggered == false) {
tmp = (#Light #Kitchen).light_currentBrightness + 20
        if (tmp > 100) {
tmp = 100
}
(#Light #Kitchen).light_moveToBrightness(tmp, 0)
        triggered = true
}
}
else {
triggered = false
}

